    given()
        .body(body)
    .when().post("/users")
    .then().statusCode(401);
}

// Datos inválidos
@Test
public void testCrearUsuarioDatosInvalidos() {
    given()
        .body("{}")
    .when().post("/users")
    .then().statusCode(400);
}
